export interface VocabItem {
  lari: string;
  mandombe: string; // accent-free for Mandombe font rendering
  french: string;
  english: string;
  portuguese?: string;
  note?: string;
  image?: string; // path to illustration image
}

export interface ConjugationTable {
  verb: string;
  verbMandombe: string;
  meaning: { fr: string; en: string; pt?: string };
  tense: string;
  tenseFr?: string;
  tensePt?: string;
  rows: { person: string; lari: string; mandombe: string }[];
}

export interface MultipleChoiceQuestion {
  type: "multiple-choice";
  question: string;
  questionFr?: string;
  questionPt?: string;
  questionMandombe?: string;
  options: string[];
  optionsFr?: string[];
  optionsPt?: string[];
  correctIndex: number;
  explanation?: string;
  explanationFr?: string;
  explanationPt?: string;
}

export interface MatchingQuestion {
  type: "matching";
  instruction: string;
  instructionFr?: string;
  instructionPt?: string;
  pairs: { left: string; leftMandombe?: string; right: string; rightFr?: string; rightPt?: string }[];
}

export interface FillInBlankQuestion {
  type: "fill-in-blank";
  sentence: string;
  sentenceFr?: string;
  sentencePt?: string;
  sentenceMandombe?: string;
  blank: string;
  hint?: string;
  hintFr?: string;
  hintPt?: string;
}

export interface CrosswordClue {
  answer: string;
  clue: string;
  clueFr?: string;
  cluePt?: string;
  row: number;
  col: number;
  direction: "across" | "down";
}

export interface CrosswordQuestion {
  type: "crossword";
  title?: string;
  titleFr?: string;
  titlePt?: string;
  gridSize: number;
  clues: CrosswordClue[];
}

export interface WordSearchClue {
  word: string;
  clue: string;
  clueFr?: string;
  cluePt?: string;
  row: number;
  col: number;
  direction: "across" | "down" | "diagonal";
}

export interface WordSearchQuestion {
  type: "word-search";
  title?: string;
  titleFr?: string;
  titlePt?: string;
  gridSize: number;
  words: WordSearchClue[];
  fillerLetters: string;
}

export interface MandombeRecognitionItem {
  mandombe: string;
  lari: string;
  distractors: string[];
  french: string;
  english?: string;
  portuguese?: string;
  mode: "glyph-to-latin" | "latin-to-glyph";
}

export interface MandombeRecognitionQuestion {
  type: "mandombe-recognition";
  title?: string;
  titleFr?: string;
  titlePt?: string;
  items: MandombeRecognitionItem[];
}

export type Exercise = MultipleChoiceQuestion | MatchingQuestion | FillInBlankQuestion | CrosswordQuestion | WordSearchQuestion | MandombeRecognitionQuestion;

export interface SyntaxExample {
  lari: string;
  mandombe: string;
  french: string;
  english: string;
  portuguese?: string;
  note?: string;
}

export interface SyntaxGroup {
  title: string;
  titleFr?: string;
  titlePt?: string;
  titleMandombe?: string;
  description?: string;
  descriptionFr?: string;
  descriptionPt?: string;
  explanation?: string;
  explanationFr?: string;
  explanationPt?: string;
  examples: SyntaxExample[];
  note?: string;
  noteFr?: string;
  notePt?: string;
}

export interface SyntaxBlock {
  title: string;
  titleFr?: string;
  titlePt?: string;
  titleMandombe?: string;
  description?: string;
  descriptionFr?: string;
  descriptionPt?: string;
  explanation?: string;
  explanationFr?: string;
  explanationPt?: string;
  pattern?: string;
  patternFr?: string;
  patternPt?: string;
  groups: SyntaxGroup[];
}

export interface Lesson {
  id: string;
  title: string;
  titleFr?: string;
  titlePt?: string;
  titleLari: string;
  titleMandombe: string;
  description: string;
  descriptionFr?: string;
  descriptionPt?: string;
  level: "beginner" | "intermediate" | "advanced";
  icon: string;
  credit?: string;
  vocabulary?: VocabItem[];
  syntax?: SyntaxBlock[];
  conjugations?: ConjugationTable[];
  phrases?: { lari: string; mandombe: string; french: string; english: string; portuguese?: string; note?: string }[];
  exercises: Exercise[];
}

